&lt;ul&gt;
&lt;li style=&quot;font-size: 12pt;&quot;&gt;&lt;span style=&quot;font-size: 12pt;&quot;&gt;Perform data profiling analysis.&lt;/span&gt;&lt;/li&gt;
&lt;li style=&quot;font-size: 12pt;&quot;&gt;&lt;span style=&quot;font-size: 12pt;&quot;&gt;Use SQL, data modeling and data integrity principles.&lt;/span&gt;&lt;/li&gt;
